class Solution:
    def countEven(self, num: int) -> int:
        def digit_sum(x):
            s = 0
            while x > 0:
                s += x % 10
                x //= 10
            return s
        return sum(1 for i in range(1, num + 1) if digit_sum(i) % 2 == 0)

solutions.python:
class Solution:
    def countEven(self, num: int) -> int:
        count = 0
        for i in range(1, num + 1):
            s = sum(int(d) for d in str(i))
            if s % 2 == 0:
                count += 1
        return count

