var countEven = function(num) {
    let count = 0;
    for (let i = 1; i <= num; i++) {
        let s = 0;
        let x = i;
        while (x > 0) {
            s += x % 10;
            x = Math.floor(x / 10);
        }
        if (s % 2 === 0) count++;
    }
    return count;
};
